  // Ensure the results view host URL page is loaded
  async ensureResultsViewHostURL(tabId: number, scanType: ScanType) {
    // The page we want to show the results view on
    const resultViewHostUrls: Record<ScanType, string> = {
      google: "https://myaccount.google.com",
      x: "https://x.com",
      linkedin: "https://www.linkedin.com",
      instagram: "https://www.instagram.com",
    };
    const resultViewHostUrl = resultViewHostUrls[scanType];
    if (!resultViewHostUrl) {
      console.error(
        "OAPOrchestrator: No result view host URL found for scan type: " +
          scanType
      );
      throw new Error(
        "OAPOrchestrator: No result view host URL found for scan type: " +
          scanType
      );
    }

    // navigate to the result view host URL
    const tab = await chrome.tabs.get(tabId);

    await chrome.tabs.update(tabId, { url: resultViewHostUrl });
    console.debug(
      "OAPOrchestrator: Navigated to result view host URL",
      tabId,
      resultViewHostUrl
    );

    await waitUntilPageLoaded(tab, resultViewHostUrl);
    console.debug("OAPOrchestrator: Page loaded", tabId, resultViewHostUrl);
  }

  async showOAPNotification(tabId: number) {
    const isScanning = await this.getScanning();
    if (isScanning) {
      console.debug(
        "OAPOrchestrator: Scan already in progress, skipping notification"
      );
      return;
    }

    // If the user has already scanned (used the OAP feature), skip the notification
    const scanStore = new ScanStore();
    const scans = await scanStore.getScans();
    if (scans.length > 0) {
      console.debug(
        "OAPOrchestrator: User has already scanned, skipping notification"
      );
      return;
    }

    console.debug("OAPOrchestrator: Showing OAP notification", tabId);
    const showOAPNotification = () => {
      // @ts-ignore
      window.showOAPNotification();
    };

    await injectScript(tabId, "oap-notification-popup.js", "ISOLATED", true);

    try {
      console.debug("OAPOrchestrator: OAP notification triggered");
      await chrome.scripting.executeScript({
        target: { tabId: tabId, allFrames: false },
        func: showOAPNotification,
        world: "ISOLATED",
        injectImmediately: false,
      });
      console.debug("OAPOrchestrator: OAP notification script injected");
    } catch (err) {
      console.error(
        "OAPOrchestrator: Error injecting notification script: ",
        err
      );
    }
  }

