  async startDeleteConnection(
    tabId: number,
    recommendation: OAPRecommendation,
    app: GoogleThirdPartyApp
  ): Promise<{
    success: boolean;
    error?: string;
    updatedRecommendation?: OAPRecommendation;
  }> {
    const title =
      chrome.i18n.getMessage("OAPActionNoticeTitleDeleteApp") ||
      "We're disconnecting the app safely";
    const continueScan = await this.showActionNoticeUI(title, tabId);
    if (continueScan === false) {
      console.debug(
        "OAPOrchestrator: OAP action notice cancelled, skipping delete connection"
      );
      return { success: false, error: "OAP action notice cancelled" };
    }

    // do the delete connection in a new tab
    const deleteConnectionTab = await openTab("https://myaccount.google.com/connections");
    await this.visitConnectedAppsPage(deleteConnectionTab.id!);

    try {
      await injectScript(deleteConnectionTab.id!, "content-oap-google.js", "MAIN", true);

      // call injected scan function (passing the deviceID as a parameter)
      const scriptRes = await chrome.scripting.executeScript({
        target: { tabId: deleteConnectionTab.id!, allFrames: false },
        func: async (app: GoogleThirdPartyApp) => {
          // @ts-ignore
          return await window.deleteConnection(app);
        },
        args: [app],
        world: "MAIN",
        injectImmediately: true,
      });

      // then close the tab
      await chrome.tabs.remove(deleteConnectionTab.id!);

      // switch to the initial tab
      await chrome.tabs.update(tabId, { active: true });

      if (scriptRes.length === 0) {
        throw new Error("OAPOrchestrator: No result from delete connection");
      }
      const { result } = scriptRes[0];
      if (result) {
        console.debug("OAPOrchestrator: Deleted connection successfully", {
          app,
          result,
        });
        console.debug("OAPOrchestrator: Updating scan store with deleted connection", app);
        const updatedRecommendation = await this.scanStore.googleUpdateWithDeletedConnection(recommendation, app);
        return { success: result, updatedRecommendation: updatedRecommendation };
      }

      console.error("OAPOrchestrator: Error deleting connection", {
        app,
        result,
      });

      return { success: result, updatedRecommendation: undefined };
    } catch (err) {
      console.error("OAPOrchestrator: Error deleting connection", err);
      return {
        success: false,
        error: err instanceof Error ? err.message : "Unknown error",
      };
    }
  }

  async startDeleteDeviceSession(
    tabId: number,
    recommendation: OAPRecommendation,
    device: GoogleDeviceSession
  ): Promise<{
    success: boolean;
    error?: string;
    updatedRecommendation?: OAPRecommendation;
  }> {
    const title =
      chrome.i18n.getMessage("OAPActionNoticeTitleDeleteDevice") ||
      "We're disconnecting the device safely";
    const continueScan = await this.showActionNoticeUI(title, tabId);
    if (continueScan === false) {
      console.debug(
        "OAPOrchestrator: OAP action notice cancelled, skipping delete device session"
      );
      return { success: false, error: "OAP action notice cancelled" };
    }

    // do the sign out in a new tab
    const signoutTabURL = `https://myaccount.google.com/device-activity/id/${device.sessionId}`;
    const signoutTab = await openTab(signoutTabURL);
    await this.visitDeviceActivityPage(signoutTab.id!, device.sessionId);

    try {
      await injectScript(signoutTab.id!, "content-oap-google.js", "MAIN", true);

      // then run the delete device session function
      // this.injectLoaderUI(tab.id!)

      // call injected scan function (passing the deviceID as a parameter)
      const scriptRes = await chrome.scripting.executeScript({
        target: { tabId: signoutTab.id!, allFrames: false },
        func: async (deviceID: string) => {
          // @ts-ignore
          return await window.deleteDeviceSession(deviceID);
        },
        args: [device.sessionId],
        world: "MAIN",
        injectImmediately: true,
      });

      // then close the tab
      await chrome.tabs.remove(signoutTab.id!);

      // switch to the initial tab
      await chrome.tabs.update(tabId, { active: true });

      if (scriptRes.length === 0) {
        throw new Error("OAPOrchestrator: No result from device ID scan");
      }
      const { result } = scriptRes[0];
      if (result) {
        console.debug("OAPOrchestrator: Deleted device session successfully", {
          device,
          result,
        });
        console.debug(
          "OAPOrchestrator: Updating scan store with deleted device session",
          device
        );
        const updatedRecommendation =
          await this.scanStore.googleUpdateWithDeletedDeviceSession(
            recommendation,
            device
          );
        return {
          success: result,
          updatedRecommendation: updatedRecommendation,
        };
      }

      console.error("OAPOrchestrator: Error deleting device session", {
        device,
        result,
      });

      return { success: result, updatedRecommendation: undefined };
    } catch (err) {
      console.error("OAPOrchestrator: Error deleting device session", err);
      return {
        success: false,
        error: err instanceof Error ? err.message : "Unknown error",
      };
    }
  }

  async visitDeviceActivityPage(tabId: number, deviceID: string) {
    const navCompleter = new Completer<void>();

    const listenerFunc = async (
      tabId: number,
      changeInfo: chrome.tabs.TabChangeInfo,
      tab: chrome.tabs.Tab
    ) => {
      if (tabId !== tab.id!) {
        return;
      }

      if (changeInfo.status !== "complete") {
        return;
      }

      if (tab.url?.includes(`/device-activity/id/${deviceID}`)) {
        navCompleter.resolve(undefined);
        return;
      }

      if (tab.url && new URL(tab.url).hostname === "accounts.google.com") {
        this.showWaitingForLoginUI(tabId);
      }
    };
    chrome.tabs.onUpdated.addListener(listenerFunc);

    // navigate to the device activity page for that device
    await chrome.scripting.executeScript({
      target: { tabId: tabId, allFrames: false },
      func: (deviceID: string) => {
        const url = `${window.location.origin}/device-activity/id/${deviceID}`;
        console.debug(
          "OAPOrchestrator: Navigating to device activity page",
          url
        );
        // insert a <a> tag with the href and click it
        const a = document.createElement("a");
        a.href = url;
        document.body.appendChild(a);
        a.click();
        console.debug(
          "OAPOrchestrator: Clicked to device activity page",
          a.href
        );
      },
      args: [deviceID],
      world: "MAIN",
      injectImmediately: true,
    });
    console.debug(
      "OAPOrchestrator: Navigating to device activity page",
      deviceID
    );

    // wait for the navigation to complete
    await navCompleter.future;
    chrome.tabs.onUpdated.removeListener(listenerFunc);
    console.debug(
      "OAPOrchestrator: Navigation to device activity page complete"
    );
  }

