import { chrome } from "@/utils/polyfill";
import {
  GoogleDeviceSession,
  GoogleDeviceSessions,
  GoogleProfileInfo,
  GoogleRecommendationTypes,
  GoogleScanResults,
  GoogleScanType,
  GoogleSecurityDetails,
  GoogleThirdPartyApp,
  isGoogleScanResults,
  isScanError,
  OAPRecommendation,
  ScanError,
  ScanResults,
} from "./types";

export function buildRecommendations(
  scanResults: ScanResults
): Array<OAPRecommendation> {
  if (isGoogleScanResults(scanResults)) {
    return buildGoogleRecommendations(scanResults);
  }

  return [];
}

function buildGoogleRecommendations(scanResults: GoogleScanResults) {
  const recommendations: Array<OAPRecommendation> = [];

  if (scanResults.securityDetails) {
    recommendations.push(
      ...buildSecurityDetailsRecommendations(scanResults.securityDetails)
    );
  }

  if (scanResults.thirdPartyApps) {
    recommendations.push(
      ...buildThirdPartyAppsRecommendations(scanResults.thirdPartyApps)
    );
  }

  if (scanResults.profileInfo) {
    recommendations.push(
      ...buildProfileInfoRecommendations(scanResults.profileInfo)
    );
  }

  if (scanResults.deviceSessions) {
    recommendations.push(
      ...buildConnectedDevicesRecommendations(scanResults.deviceSessions)
    );
  }

  return recommendations;
}

function buildSecurityDetailsRecommendations(
  securityDetails: GoogleSecurityDetails | ScanError
): Array<OAPRecommendation> {
  if (isScanError(securityDetails)) {
    return [
      {
        scanType: "google",
        type: "google-2fa-status",
        importance: "high",
        categoryLabel: getTranslatedMessage("oapCategorySecurity"),
        resolved: false,
        isError: true,
        unresolvedInfo: {
          title: getTranslatedMessage("oap2faUnresolvedTitle"),
          explanation: "",
        }
      },
      {
        scanType: "google",
        type: "google-recovery-email",
        importance: "medium",
        categoryLabel: getTranslatedMessage("oapCategorySecurity"),
        resolved: false,
        isError: true,
        unresolvedInfo: {
          title: getTranslatedMessage("oapRecoveryEmailUnresolvedTitle"),
          explanation: "",
        }
      },
      {
        scanType: "google",
        type: "google-recovery-phone",
        importance: "medium",
        categoryLabel: getTranslatedMessage("oapCategorySecurity"),
        resolved: false,
        isError: true,
        unresolvedInfo: {
          title: getTranslatedMessage("oapRecoveryPhoneUnresolvedTitle"),
          explanation: "",
        }
      },
      {
        scanType: "google",
        type: "google-password-change",
        importance: "low",
        categoryLabel: getTranslatedMessage("oapCategorySecurity"),
        resolved: false,
        isError: true,
        unresolvedInfo: {
          title: getTranslatedMessage("oapPasswordChangeUnresolvedTitle"),
          explanation: "",
        }
      },
    ];
  }

  // 2FA status
  const isTwoFactorEnabled = securityDetails.twoFactorStatus === "on";
  // Recovery email
  const recoveryEmail = securityDetails.recoveryEmail;
  // Recovery phone
  const recoveryPhone = securityDetails.recoveryPhone;
  // Password change
  const passwordLastChangeStr = securityDetails.passwordLastChange;
  const passwordLastChange = passwordLastChangeStr
    ? new Date(passwordLastChangeStr)
    : undefined;
  // check if password last change is more than 6 months ago
  const isPasswordLastChangeOld =
    passwordLastChange &&
    Date.now() - passwordLastChange.getTime() > 6 * 30 * 24 * 60 * 60 * 1000;

  return [
    {
      scanType: "google",
      type: "google-2fa-status",
      importance: "high",
      categoryLabel: getTranslatedMessage("oapCategorySecurity"),
      resolved: isTwoFactorEnabled,
      whatToDoTitle: getTranslatedMessage("oap2faWhatToDoTitle"),
      unresolvedInfo: {
        title: getTranslatedMessage("oap2faUnresolvedTitle"),
        explanation: getTranslatedMessage("oap2faUnresolvedExplanation"),
        whatToDo: [
          `<link https://myaccount.google.com/security>${getTranslatedMessage(
            "oap2faWhatToDoStep1"
          )}</link>`,
          getTranslatedMessage("oap2faWhatToDoStep2"),
        ],
      },
      resolvedInfo: {
        title: getTranslatedMessage("oap2faResolvedTitle"),
        explanation: "",
        actionMessage: getTranslatedMessage("oap2faResolvedActionMessage"),
      },
    },
    {
      scanType: "google",
      type: "google-recovery-email",
      importance: "medium",
      categoryLabel: getTranslatedMessage("oapCategorySecurity"),
      resolved: !!recoveryEmail,
      whatToDoTitle: getTranslatedMessage("oapRecoveryEmailWhatToDoTitle"),
      unresolvedInfo: {
        title: getTranslatedMessage("oapRecoveryEmailUnresolvedTitle"),
        explanation: getTranslatedMessage(
          "oapRecoveryEmailUnresolvedExplanation"
        ),
        whatToDo: [
          `<link https://myaccount.google.com/security>${getTranslatedMessage(
            "oapRecoveryEmailWhatToDoStep1"
          )}</link>`,
          getTranslatedMessage("oapRecoveryEmailWhatToDoStep2"),
          getTranslatedMessage("oapRecoveryEmailWhatToDoStep3"),
        ],
      },
      resolvedInfo: {
        title: getTranslatedMessage("oapRecoveryEmailResolvedTitle"),
        explanation: "",
        actionMessage: getTranslatedMessage(
          "oapRecoveryEmailResolvedActionMessage"
        ),
      },
    },
    {
      scanType: "google",
      type: "google-recovery-phone",
      importance: "medium",
      categoryLabel: getTranslatedMessage("oapCategorySecurity"),
      resolved: !!recoveryPhone,
      whatToDoTitle: getTranslatedMessage("oapRecoveryPhoneWhatToDoTitle"),
      unresolvedInfo: {
        title: getTranslatedMessage("oapRecoveryPhoneUnresolvedTitle"),
        explanation: getTranslatedMessage(
          "oapRecoveryPhoneUnresolvedExplanation"
        ),
        whatToDo: [
          `<link https://myaccount.google.com/security>${getTranslatedMessage(
            "oapRecoveryPhoneWhatToDoStep1"
          )}</link>`,
          getTranslatedMessage("oapRecoveryPhoneWhatToDoStep2"),
          getTranslatedMessage("oapRecoveryPhoneWhatToDoStep3"),
        ],
      },
      resolvedInfo: {
        title: getTranslatedMessage("oapRecoveryPhoneResolvedTitle"),
        explanation: "",
        actionMessage: getTranslatedMessage(
          "oapRecoveryPhoneResolvedActionMessage"
        ),
      },
    },
    {
      scanType: "google",
      type: "google-password-change",
      importance: "low",
      categoryLabel: getTranslatedMessage("oapCategorySecurity"),
      resolved: !isPasswordLastChangeOld,
      unresolvedInfo: {
        title: getTranslatedMessage("oapPasswordChangeUnresolvedTitle"),
        explanation: getTranslatedMessage(
          "oapPasswordChangeUnresolvedExplanation"
        ),
        whatToDo: [
          `<link https://myaccount.google.com/security>${getTranslatedMessage(
            "oapPasswordChangeWhatToDoStep1"
          )}</link>`,
          getTranslatedMessage("oapPasswordChangeWhatToDoStep2"),
        ],
      },
      resolvedInfo: {
        title: getTranslatedMessage("oapPasswordChangeResolvedTitle"),
        explanation: "",
        actionMessage: getTranslatedMessage(
          "oapPasswordChangeResolvedActionMessage"
        ),
      },
    },
  ];
}

function buildThirdPartyAppsRecommendations(
  thirdPartyApps: GoogleThirdPartyApp[] | ScanError
): Array<OAPRecommendation> {
  if (isScanError(thirdPartyApps)) {
    return [
      {
        scanType: "google",
        type: "google-apps-basic-access",
        importance: "medium",
        categoryLabel: getTranslatedMessage("oapCategoryPrivacy"),
        resolved: false,
        isError: true,
        unresolvedInfo: {
          title: getTranslatedMessage("oapAppsBasicAccessUnresolvedTitle"),
          explanation: "",
        }
      },
      {
        scanType: "google",
        type: "google-apps-extended-access",
        importance: "high",
        categoryLabel: getTranslatedMessage("oapCategoryPrivacy"),
        resolved: false,
        isError: true,
        unresolvedInfo: {
          title: getTranslatedMessage("oapAppsExtendedAccessUnresolvedTitle"),
          explanation: "",
        }
      },
    ];
  }

  // 3rd party apps - Basic access
  const basicAccessApps = thirdPartyApps.filter(
    (app) => app.permissions.length === 1 && app.permissions[0].weight === 0
  );

  // 3rd party apps - Extended access
  const extendedAccessApps = thirdPartyApps.filter((app) =>
    app.permissions.some((p) => p.weight > 0)
  );

  return [
    {
      scanType: "google",
      type: "google-apps-basic-access",
      importance: "medium",
      categoryLabel: getTranslatedMessage("oapCategoryPrivacy"),
      resolved: !basicAccessApps || basicAccessApps.length === 0,
      whatToDoTitle: getTranslatedMessage("oapAppsBasicAccessWhatToDoTitle"),
      unresolvedInfo: {
        title: getTranslatedMessage("oapAppsBasicAccessUnresolvedTitle"),
        explanation: getTranslatedMessage(
          "oapAppsBasicAccessUnresolvedExplanation"
        ),
        whatToDo:
          basicAccessApps && basicAccessApps.length > 0
            ? [
                // `<route 'google-apps-basic-access'>View ${basicAccessApps?.length} apps</route>`,
                `<route 'google-apps-basic-access'>${getTranslatedMessage(
                  "oapAppsBasicAccessWhatToDoStep1",
                  [basicAccessApps?.length.toString()]
                )}</route>`,
                getTranslatedMessage("oapAppsBasicAccessWhatToDoStep2"),
              ]
            : [],
      },
      resolvedInfo: {
        title: getTranslatedMessage("oapAppsBasicAccessResolvedTitle"),
        explanation: "",
        actionMessage: getTranslatedMessage(
          "oapAppsBasicAccessResolvedActionMessage"
        ),
      },
    },
    {
      scanType: "google",
      type: "google-apps-extended-access",
      importance: "high",
      categoryLabel: getTranslatedMessage("oapCategoryPrivacy"),
      resolved: !extendedAccessApps || extendedAccessApps.length === 0,
      whatToDoTitle: getTranslatedMessage("oapAppsExtendedAccessWhatToDoTitle"),
      unresolvedInfo: {
        title: getTranslatedMessage("oapAppsExtendedAccessUnresolvedTitle"),
        explanation: getTranslatedMessage(
          "oapAppsExtendedAccessUnresolvedExplanation"
        ),
        whatToDo:
          extendedAccessApps && extendedAccessApps.length > 0
            ? [
                // `<route 'google-apps-extended-access'>View ${extendedAccessApps?.length} apps</route>`,
                `<route 'google-apps-extended-access'>${getTranslatedMessage(
                  "oapAppsExtendedAccessWhatToDoStep1",
                  [extendedAccessApps?.length.toString()]
                )}</route>`,
                getTranslatedMessage("oapAppsExtendedAccessWhatToDoStep2"),
              ]
            : [],
      },
      resolvedInfo: {
        title: getTranslatedMessage("oapAppsExtendedAccessResolvedTitle"),
        explanation: "",
        actionMessage: getTranslatedMessage(
          "oapAppsExtendedAccessResolvedActionMessage"
        ),
      },
    },
  ];
}

function buildProfileInfoRecommendations(
  profileInfo: GoogleProfileInfo | ScanError
): Array<OAPRecommendation> {
  if (isScanError(profileInfo)) {
    return [
      {
        scanType: "google",
        type: "google-public-profile-info",
        importance: "medium",
        categoryLabel: getTranslatedMessage("oapCategoryPrivacy"),
        resolved: false,
        isError: true,
        unresolvedInfo: {
          title: getTranslatedMessage("oapPublicProfileUnresolvedTitle"),
          explanation: "",
        }
      },
    ];
  }

  // Publicly available profile info
  const isBirthdayPublic = profileInfo.birthday?.visibility === "public";
  const isGenderPublic = profileInfo.gender?.visibility === "public";

  return [
    {
      scanType: "google",
      type: "google-public-profile-info",
      importance: "medium",
      categoryLabel: getTranslatedMessage("oapCategoryPrivacy"),
      resolved: !isBirthdayPublic && !isGenderPublic,
      unresolvedInfo: {
        title: getTranslatedMessage("oapPublicProfileUnresolvedTitle"),
        explanation: getTranslatedMessage(
          "oapPublicProfileUnresolvedExplanation"
        ),
        whatToDo: [
          getTranslatedMessage("oapPublicProfileWhatToDoStep1"),
          getTranslatedMessage("oapPublicProfileWhatToDoStep2"),
        ],
      },
      resolvedInfo: {
        title: getTranslatedMessage("oapPublicProfileResolvedTitle"),
        explanation: "",
        actionMessage: getTranslatedMessage(
          "oapPublicProfileResolvedActionMessage"
        ),
      },
    },
  ];
}

function buildConnectedDevicesRecommendations(deviceSessions: GoogleDeviceSessions | ScanError): Array<OAPRecommendation> {
  if (isScanError(deviceSessions)) {
    return [
      {
        scanType: "google",
        type: "google-connected-devices",
        importance: "medium",
        categoryLabel: getTranslatedMessage("oapCategoryPrivacy"),
        resolved: false,
        isError: true,
      },
    ];
  }

  // Connected devices
  const hasConnectedDevices =
    deviceSessions &&
    Object.keys(deviceSessions).length > 0;
  return [{
    scanType: "google",
    type: "google-connected-devices",
    importance: "medium",
    categoryLabel: getTranslatedMessage("oapCategoryPrivacy"),
    resolved: !hasConnectedDevices,
    whatToDoTitle: getTranslatedMessage("oapConnectedDevicesWhatToDoTitle"),
    unresolvedInfo: {
      title: getTranslatedMessage("oapConnectedDevicesUnresolvedTitle"),
      explanation: getTranslatedMessage(
        "oapConnectedDevicesUnresolvedExplanation"
      ),
      whatToDo: hasConnectedDevices
        ? [
            `<route 'google-connected-devices'>${getTranslatedMessage(
              "oapConnectedDevicesWhatToDoStep1",
              [Object.keys(deviceSessions || {}).length.toString()]
            )}</route>`,
            getTranslatedMessage("oapConnectedDevicesWhatToDoStep2"),
          ]
        : [],
    },
    resolvedInfo: {
      title: getTranslatedMessage("oapConnectedDevicesResolvedTitle"),
      explanation: "",
      actionMessage: getTranslatedMessage(
        "oapConnectedDevicesResolvedActionMessage"
      ),
    },
  },];
}

export function googleRecommendationTypeToScanType(
  recommendationType: GoogleRecommendationTypes
): GoogleScanType | undefined {
  switch (recommendationType) {
    case "google-2fa-status":
      return "securityDetails";
    case "google-recovery-email":
      return "profileInfo";
    case "google-recovery-phone":
      return "profileInfo";
    case "google-password-change":
      return "securityDetails";
    case "google-public-profile-info":
      return "profileInfo";
    case "google-apps-basic-access":
      return "thirdPartyApps";
    case "google-apps-extended-access":
      return "thirdPartyApps";
    case "google-connected-devices":
      return "deviceSessions";
    default:
      return undefined;
  }
}

function getTranslatedMessage(
  key: string,
  substitutions?: string | string[]
): string {
  try {
    return chrome.i18n.getMessage(key, substitutions) || key;
  } catch (error) {
    console.warn(`Translation key "${key}" not found:`, error);
    return key;
  }
}
